#include <stdio.h>
int main() {
    int T, N, X, Ai;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &X);
        int found = 0;
        for (int i = 0; i < N; i++) {
            scanf("%d", &Ai);
            if (Ai >= X) {
                found = 1;
                break;
            }
        }
        if (found) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

