code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int X = sc.nextInt();
            boolean found = false;
            for (int i = 0; i < N; i++) {
                int Ai = sc.nextInt();
                if (Ai >= X) {
                    found = true;
                    break;
                }
            }
            if (found) System.out.println("YES");
            else System.out.println("NO");
        }
    }
}

