const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, X] = readline().split(' ').map(Number);
    const A = readline().split(' ').map(Number);
    let found = false;
    for (let j = 0; j < N; j++) {
        if (A[j] >= X) {
            found = true;
            break;
        }
    }
    console.log(found ? 'YES' : 'NO');
}

